1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	const BIRTH_NEIGHBORS = 3;
9	const SURVIVAL_NEIGHBORS = 2;
10	
11	function key(x: number, y: number): string {
12	  return `${x},${y}`;
13	}
14	
15	function parseKey(cellKey: string): Cell {
16	  const [x, y] = cellKey.split(",").map(Number);
17	  return [x, y];
18	}
19	
20	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
21	  const counts = new Map<string, number>();
22	  for (const [x, y] of cells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const neighbor = key(x + dx, y + dy);
25	      counts.set(neighbor, (counts.get(neighbor) ?? 0) + 1);
26	    }
27	  }
28	  return counts;
29	}
30	
31	export function nextGeneration(cells: Cell[]): Cell[] {
32	  const living = new Set(cells.map(([x, y]) => key(x, y)));
33	  const neighborCounts = countLiveNeighbors(cells);
34	
35	  const next: Cell[] = [];
36	  for (const [cellKey, count] of neighborCounts) {
37	    const survives = count === SURVIVAL_NEIGHBORS && living.has(cellKey);
38	    const born = count === BIRTH_NEIGHBORS;
39	    if (survives || born) {
40	      next.push(parseKey(cellKey));
41	    }
42	  }
43	  return next;
44	}
